-- Generated by render.py — SELF-CONTAINED deploy for Snowflake Workspaces.
-- Run the whole file in a Workspace SQL worksheet (Run All). No CLI / PUT / Python.
-- Synthetic demo data (seed=42, today=2026-06-22); chat tables stay empty.
-- Prereq: GRANT DATABASE ROLE SNOWFLAKE.CORTEX_USER TO ROLE SYSADMIN;

-- 1) Warehouse + database + schema
USE ROLE SYSADMIN;
CREATE WAREHOUSE IF NOT EXISTS DEMO_WH
    WAREHOUSE_SIZE = XSMALL AUTO_SUSPEND = 60 AUTO_RESUME = TRUE INITIALLY_SUSPENDED = TRUE;
CREATE DATABASE IF NOT EXISTS DEMO_EMPLOYEE_APP COMMENT = 'Cortex Dashboard Kit demo — synthetic data';
CREATE SCHEMA IF NOT EXISTS DEMO_EMPLOYEE_APP.PUBLIC;
USE SCHEMA DEMO_EMPLOYEE_APP.PUBLIC;
USE WAREHOUSE DEMO_WH;

-- 2) Tables

CREATE OR REPLACE TABLE BUSINESS_UNITS (  -- one row per top-level business unit
    BU_ID NUMBER PRIMARY KEY,
    NAME VARCHAR(80),
    HEAD_USER_ID NUMBER
);
CREATE OR REPLACE TABLE DEPARTMENTS_DETAIL (  -- one row per department
    DEPT_ID NUMBER PRIMARY KEY,
    DEPT_NAME VARCHAR(100),
    BU_ID NUMBER,
    HEAD_USER_ID NUMBER
);
CREATE OR REPLACE TABLE EMPLOYEES (  -- one row per employee
    EMPLOYEE_ID NUMBER PRIMARY KEY,
    FIRST_NAME VARCHAR(80),
    LAST_NAME VARCHAR(80),
    EMAIL VARCHAR(150),
    DEPARTMENT VARCHAR(100),
    TITLE VARCHAR(150),
    LOCATION VARCHAR(100),
    STATUS VARCHAR(20),
    HIRE_DATE DATE,
    TERMINATION_DATE DATE,
    MANAGER_ID NUMBER,
    BUSINESS_UNIT_ID NUMBER,
    LATTICE_ID VARCHAR(64),
    FRESHTEAM_ID VARCHAR(64)
);
CREATE OR REPLACE TABLE EMPLOYEE_FIELDS (  -- one row per employee (extended HR fields)
    EMPLOYEE_ID NUMBER PRIMARY KEY,
    EMPLOYMENT_TYPE VARCHAR(40),
    PHONE VARCHAR(40),
    NATIONALITY VARCHAR(60),
    GENDER VARCHAR(20),
    DATE_OF_BIRTH DATE,
    NOTICE_PERIOD_DAYS NUMBER
);
CREATE OR REPLACE TABLE HEADCOUNT_PLAN (  -- one row per month (planned workforce)
    PLAN_ID NUMBER PRIMARY KEY,
    MONTH DATE,
    DEPARTMENT VARCHAR(50),
    PLANNED_FTE NUMBER,
    PLANNED_CONTRACTORS NUMBER,
    PLANNED_MANAGED NUMBER
);
CREATE OR REPLACE TABLE TASKS (  -- one row per task type
    TASK_ID NUMBER PRIMARY KEY,
    TASK_NAME VARCHAR(80),
    IS_BILLABLE_DEFAULT BOOLEAN
);
CREATE OR REPLACE TABLE PROJECTS (  -- one row per client project
    PROJECT_ID NUMBER PRIMARY KEY,
    PROJECT_NAME VARCHAR(150),
    CLIENT VARCHAR(150),
    STATUS VARCHAR(20),
    START_DATE DATE,
    END_DATE DATE,
    HOURLY_RATE NUMBER,
    IS_BILLABLE BOOLEAN
);
CREATE OR REPLACE TABLE PROJECT_ASSIGNMENTS (  -- one row per employee-project allocation
    ASSIGNMENT_ID NUMBER PRIMARY KEY,
    EMPLOYEE_ID NUMBER,
    PROJECT_ID NUMBER,
    ROLE VARCHAR(80),
    ALLOCATION_PCT NUMBER,
    IS_PROJECT_MANAGER BOOLEAN
);
CREATE OR REPLACE TABLE TIME_ENTRIES (  -- one row per logged time entry
    ENTRY_ID NUMBER PRIMARY KEY,
    EMPLOYEE_ID NUMBER,
    PROJECT_ID NUMBER,
    TASK_ID NUMBER,
    SPENT_DATE DATE,
    HOURS FLOAT,
    IS_BILLABLE BOOLEAN,
    NOTES VARCHAR
);
CREATE OR REPLACE TABLE PERFORMANCE_REVIEWS (  -- one row per review
    REVIEW_ID NUMBER PRIMARY KEY,
    EMPLOYEE_ID NUMBER,
    REVIEW_DATE DATE,
    REVIEW_PERIOD VARCHAR(20),
    RATING FLOAT,
    SENTIMENT VARCHAR(20),
    SENTIMENT_SCORE FLOAT,
    GOALS_MET NUMBER,
    GOALS_TOTAL NUMBER,
    MANAGER_COMMENTS VARCHAR
);
CREATE OR REPLACE TABLE LEAVE_REQUESTS (  -- one row per leave request
    LEAVE_ID NUMBER PRIMARY KEY,
    EMPLOYEE_ID NUMBER,
    LEAVE_TYPE VARCHAR(30),
    START_DATE DATE,
    DAYS NUMBER,
    STATUS VARCHAR(20),
    REASON VARCHAR
);
CREATE OR REPLACE TABLE COMPANY_KNOWLEDGE_BASE (  -- one row per knowledge-base document
    DOC_ID NUMBER PRIMARY KEY,
    TITLE VARCHAR(200),
    CATEGORY VARCHAR(80),
    AUDIENCE VARCHAR(40),
    CONTENT VARCHAR
);
CREATE OR REPLACE TABLE CHAT_SESSIONS (  -- one row per chat conversation (written by the app)
    SESSION_ID NUMBER AUTOINCREMENT PRIMARY KEY,
    USERNAME VARCHAR(150),
    SESSION_NAME VARCHAR(200),
    CREATED_AT TIMESTAMP_NTZ DEFAULT CURRENT_TIMESTAMP(),
    LAST_ACTIVE TIMESTAMP_NTZ DEFAULT CURRENT_TIMESTAMP()
);
CREATE OR REPLACE TABLE CHAT_MESSAGES (  -- one row per chat message (written by the app)
    MESSAGE_ID NUMBER AUTOINCREMENT PRIMARY KEY,
    SESSION_ID NUMBER,
    USERNAME VARCHAR(150),
    ROLE VARCHAR(20),
    CONTENT VARCHAR,
    SOURCES VARCHAR,
    CREATED_AT TIMESTAMP_NTZ DEFAULT CURRENT_TIMESTAMP()
);

-- 3) Seed data (synthetic; INSERTed inline so no stage/PUT is needed)
-- BUSINESS_UNITS — one row per top-level business unit

-- DEPARTMENTS_DETAIL — one row per department

-- EMPLOYEES — one row per employee

-- EMPLOYEE_FIELDS — one row per employee (extended HR fields)

-- HEADCOUNT_PLAN — one row per month (planned workforce)

-- TASKS — one row per task type

-- PROJECTS — one row per client project

-- PROJECT_ASSIGNMENTS — one row per employee-project allocation

-- TIME_ENTRIES — one row per logged time entry

-- PERFORMANCE_REVIEWS — one row per review

-- LEAVE_REQUESTS — one row per leave request

-- COMPANY_KNOWLEDGE_BASE — one row per knowledge-base document

-- 4) Cortex Search service for the RAG knowledge base
USE SCHEMA DEMO_EMPLOYEE_APP.PUBLIC;
USE WAREHOUSE DEMO_WH;

CREATE OR REPLACE CORTEX SEARCH SERVICE COMPANY_KB_SEARCH
    ON CONTENT
    ATTRIBUTES CATEGORY, TITLE, AUDIENCE
    WAREHOUSE = DEMO_WH
    TARGET_LAG = '1 hour'
    EMBEDDING_MODEL = 'snowflake-arctic-embed-m-v1.5'
    AS SELECT CONTENT, CATEGORY, TITLE, AUDIENCE FROM DEMO_EMPLOYEE_APP.PUBLIC.COMPANY_KNOWLEDGE_BASE;

-- 5) Verification — every data table should be non-empty
SELECT * FROM (
    SELECT 'BUSINESS_UNITS' AS TBL, COUNT(*) AS N FROM BUSINESS_UNITS
    UNION ALL SELECT 'DEPARTMENTS_DETAIL' AS TBL, COUNT(*) AS N FROM DEPARTMENTS_DETAIL
    UNION ALL SELECT 'EMPLOYEES' AS TBL, COUNT(*) AS N FROM EMPLOYEES
    UNION ALL SELECT 'EMPLOYEE_FIELDS' AS TBL, COUNT(*) AS N FROM EMPLOYEE_FIELDS
    UNION ALL SELECT 'HEADCOUNT_PLAN' AS TBL, COUNT(*) AS N FROM HEADCOUNT_PLAN
    UNION ALL SELECT 'TASKS' AS TBL, COUNT(*) AS N FROM TASKS
    UNION ALL SELECT 'PROJECTS' AS TBL, COUNT(*) AS N FROM PROJECTS
    UNION ALL SELECT 'PROJECT_ASSIGNMENTS' AS TBL, COUNT(*) AS N FROM PROJECT_ASSIGNMENTS
    UNION ALL SELECT 'TIME_ENTRIES' AS TBL, COUNT(*) AS N FROM TIME_ENTRIES
    UNION ALL SELECT 'PERFORMANCE_REVIEWS' AS TBL, COUNT(*) AS N FROM PERFORMANCE_REVIEWS
    UNION ALL SELECT 'LEAVE_REQUESTS' AS TBL, COUNT(*) AS N FROM LEAVE_REQUESTS
    UNION ALL SELECT 'COMPANY_KNOWLEDGE_BASE' AS TBL, COUNT(*) AS N FROM COMPANY_KNOWLEDGE_BASE
) ORDER BY N ASC, TBL;

